/**
 * Helper class for Min Priority Queue
 */
class MinPriorityQueue {
    constructor() {
        // Stores elements as [cost, index]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Compares based on cost (index 0)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        let parentIndex = Math.floor((index - 1) / 2);
        while (index > 0 && this._compare(index, parentIndex)) {
            this._swap(index, parentIndex);
            index = parentIndex;
            parentIndex = Math.floor((index - 1) / 2);
        }
    }

    _bubbleDown(index) {
        let leftChild = 2 * index + 1;
        let rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this._compare(leftChild, smallest)) {
            smallest = leftChild;
        }
        if (rightChild < this.heap.length && this._compare(rightChild, smallest)) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            this._swap(index, smallest);
            this._bubbleDown(smallest);
        }
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}

function solve(nums, queries) {
    const N = nums.length;

    // 1. Precompute closest(x)
    const closest = new Array(N);
    for (let x = 0; x < N; x++) {
        if (x === 0) {
            closest[x] = 1; // Only neighbor is 1
        } else if (x === N - 1) {
            closest[x] = N - 2; // Only neighbor is N-2
        } else {
            // Neighbors are x-1 and x+1
            const costLeft = nums[x] - nums[x - 1];
            const costRight = nums[x + 1] - nums[x];

            if (costLeft <= costRight) {
                // Tie-breaker: choose smaller index (x-1)
                closest[x] = x - 1;
            } else {
                closest[x] = x + 1;
            }
        }
    }

    const results = [];

    // 2. Process each query using Dijkstra's Algorithm
    for (const [start, target] of queries) {
        // Initialize distances array
        const dist = new Array(N).fill(Infinity);
        const pq = new MinPriorityQueue();

        dist[start] = 0;
        // PQ stores [cost, index]
        pq.enqueue([0, start]);

        let minCost = Infinity;

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) {
                continue;
            }

            if (u === target) {
                minCost = d;
                break; // Found shortest path to target
            }

            // --- Relaxation Step 1: Type B Move (Closest Neighbor) ---
            const c = closest[u];
            const newCostB = d + 1;

            if (newCostB < dist[c]) {
                dist[c] = newCostB;
                pq.enqueue([newCostB, c]);
            }

            // --- Relaxation Step 2: Type A Move (Jump to any v) ---
            // This is the O(N) step per node extraction, leading to O(N^2) overall per query.
            for (let v = 0; v < N; v++) {
                // Cost is absolute difference in values
                const jumpCost = Math.abs(nums[u] - nums[v]);
                const newCostA = d + jumpCost;

                if (newCostA < dist[v]) {
                    dist[v] = newCostA;
                    pq.enqueue([newCostA, v]);
                }
            }
        }

        results.push(minCost);
    }

    return results;
}

