/**
 * Helper class for Min Priority Queue
 */
class MinPriorityQueue {
    constructor() {
        // Stores elements as [cost, index]
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    // Compares based on cost (index 0)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        let parentIndex = Math.floor((index - 1) / 2);
        while (index > 0 && this._compare(index, parentIndex)) {
            this._swap(index, parentIndex);
            index = parentIndex;
            parentIndex = Math.floor((index - 1) / 2);
        }
    }

    _bubbleDown(index) {
        let leftChild = 2 * index + 1;
        let rightChild = 2 * index + 2;
        let smallest = index;

        if (leftChild < this.heap.length && this._compare(leftChild, smallest)) {
            smallest = leftChild;
        }
        if (rightChild < this.heap.length && this._compare(rightChild, smallest)) {
            smallest = rightChild;
        }

        if (smallest !== index) {
            this._swap(index, smallest);
            this._bubbleDown(smallest);
        }
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}

